revision.text:
.wpss-cat {
	text-align:center;
	background:#addfad;
}


@media screen {
    html.skin-theme-clientpref-night .wpss-cat {
		background:#0e250e;
	}
}


@media screen and ( prefers-color-scheme: dark) {
	html.skin-theme-clientpref-os .wpss-cat {
		background:#0e250e;
	}
}

